CREATE TABLE Adopter (
    adopterID   INT PRIMARY KEY,
    name        VARCHAR(100) NOT NULL,
    phoneNumber VARCHAR(30),
    address     VARCHAR(150)
);

CREATE TABLE Pet (
    petID   INT PRIMARY KEY,
    name    VARCHAR(100) NOT NULL,
    species VARCHAR(50)
);

CREATE TABLE Adoption (
    adoptionID   INT PRIMARY KEY,
    adopterID    INT NOT NULL,
    petID        INT NOT NULL,
    fee          DECIMAL(10,2),
    adoptionDate DATE NOT NULL,
    FOREIGN KEY (adopterID) REFERENCES Adopter(adopterID),
    FOREIGN KEY (petID)     REFERENCES Pet(petID)
);



SELECT a.name
FROM Adopter AS a
INNER JOIN Adoption AS b ON a.adopterID = b.adopterID
WHERE date(b.adoptionDate) = '2025-11-01';